/**
 * Markdown to HTML converter for Telegram
 */

const MAX_TELEGRAM = 4096;
const SAFE_BUDGET = 4000;

function escapeHtml(text) {
  if (!text) return '';
  return String(text)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}

function markdownToHtml(inputText) {
  if (!inputText) return '';
  let text = String(inputText);
  const placeholders = [];
  let placeholderIndex = 0;

  const addPlaceholder = (html) => {
    const ph = `\x00PH${placeholderIndex++}\x00`;
    placeholders.push({ ph, html });
    return ph;
  };

  text = text.replace(/```([\s\S]*?)```/g, (m, code) => {
    return addPlaceholder(`<pre>${escapeHtml(code.trim())}</pre>`);
  });

  text = text.replace(/`([^`\n]+)`/g, (m, code) => {
    return addPlaceholder(`<code>${escapeHtml(code)}</code>`);
  });

  text = text.replace(/\[([^\]]+)\]\(([^)]+)\)/g, (m, label, url) => {
    return addPlaceholder(`<a href="${url.trim()}">${escapeHtml(label)}</a>`);
  });

  text = text.replace(/\*\*([^*]+)\*\*/g, (m, content) => {
    return addPlaceholder(`<b>${escapeHtml(content)}</b>`);
  });

  text = text.replace(/(?<!\*)\*([^*\n]+)\*(?!\*)/g, (m, content) => {
    return addPlaceholder(`<i>${escapeHtml(content)}</i>`);
  });

  text = escapeHtml(text);

  for (const { ph, html } of placeholders) {
    text = text.replace(ph, html);
  }

  text = text.replace(/\n{3,}/g, '\n\n');
  return text.trim();
}

function chunkForTelegram(text, maxLen = SAFE_BUDGET) {
  if (!text || text.length <= maxLen) return [text || ''];
  const parts = [];
  const paragraphs = text.split(/\n{2,}/);

  for (const p of paragraphs) {
    if (p.length <= maxLen) {
      parts.push(p);
    } else {
      const lines = p.split('\n');
      for (const line of lines) {
        if (line.length <= maxLen) {
          parts.push(line);
        } else {
          const re = new RegExp(`.{1,${maxLen}}`, 'g');
          const pieces = line.match(re) || [];
          parts.push(...pieces);
        }
      }
    }
  }
  return parts.filter(p => p.length > 0);
}

const inputItems = $input.all();
const out = [];

for (const item of inputItems) {
  const j = item.json || {};
  const raw = j.output ?? j.message ?? j.text ?? j.content ?? '';
  const formatted = markdownToHtml(raw);
  const chunks = chunkForTelegram(formatted, SAFE_BUDGET);

  chunks.forEach((chunk, idx) => {
    out.push({
      json: { ...j, output: chunk, message: chunk, part_index: idx + 1, parts_total: chunks.length },
      binary: item.binary,
    });
  });
}

return out;
